// Spanning path: coalesce across chunks.
const out = new Uint8Array(size);
let copied = 0;
while (copied < size) {
  const c = this.chunks[0];
  const n = Math.min(c.length - this.head, size - copied);
  out.set(c.subarray(this.head, this.head + n), copied);
  copied += n;
  this.head += n;
  this.total -= n;
  if (this.head === c.length) { this.chunks.shift(); this.head = 0; }
}
return out;

function parseNonNegativeInt(s: string | null | undefined): number | undefined {
  if (s === null || s === undefined) return undefined;
  // SB-4: strict digits only; reject "123abc", "1e3", etc before Number coercion.
  if (!/^\d+$/.test(s)) return undefined;
  const n = Number(s);
  if (!Number.isFinite(n) || n < 0) return undefined;
  return n;
}

