const makeInfo = (d: number): RangeNegotiation => {
  if (!info) {
    info = { requested, honored, delivered: d, absoluteStart: start };
    if (fullSize !== undefined) info.fullSize = fullSize;
    if (etagFromResponse) info.etag = etagFromResponse;
